     9→  StreamSubscription<List<ConnectivityResult>>? _subscription;
    10→
    11→  @override
    12→  bool build() {
    13→    // Initialize as false until we get a real reading
    14→    _initializeConnectivity();
    15→    ref.onDispose(() {
    16→      _subscription?.cancel();
    17→    });
    18→    return false;
    19→  }
    20→
    21→  Future<void> _initializeConnectivity() async {
    22→    try {
    23→      final results = await Connectivity().checkConnectivity();
    24→      _updateConnectionState(results);
    25→
    26→      _subscription = Connectivity().onConnectivityChanged.listen(
    27→        _updateConnectionState,
    28→        onError: (error) {
    29→          state = false; // Assume offline on errors
    30→        },
    31→      );
    32→    } catch (e) {
    33→      state = false; // Assume offline on errors
    34→    }
    35→  }
    36→
    37→  void _updateConnectionState(List<ConnectivityResult> results) {
    38→    // Consider online if any connection type is available
    39→    state = results.any((result) => result != ConnectivityResult.none);
    40→  }
    41→}
